  ('dietitian-moex-09828', 'dietitian', 'dietitian-moex-096-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '陳先生60歲、身高170公分，每週固定洗腎3次，IBW定為62 kg，目前洗腎前體重常為65~66 kg，血 磷值過高，下列有關為他設計的飲食計畫，何者錯誤？', '["熱量：30 kcal × 62＝1860 kcal", "蛋白質：0.8 g × 65＝52 g，60% HBV", "水分攝取：前一天液體排出量加750~1000毫升，但以兩次洗腎間，體重增加＜5% IBW為目標", "限磷＜1200 mg/天"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "ce96bddf0732", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096130", "c": "113", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "096", "exam_name": "096年第二次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐、醫師分試考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
